CREATE TABLE `biz_log`( `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID', `method_name` varchar(50) NOT NULL COMMENT '方法名称', `description` varchar(30) NOT NULL COMMENT '描述', `request_ip` varchar(15) NOT NULL COMMENT '请求ip', `browser` varchar(200) NULL COMMENT '浏览器', `url` varchar(100) NOT NULL COMMENT '请求地址', `param` varchar(300) NULL COMMENT '请求参数', `time` int NOT NULL COMMENT '耗时', `exception` varchar(300) NULL COMMENT '异常', `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '状态 1:成功 0:失败', `create_user_id` bigint NOT NULL COMMENT '创建人ID', `create_user_name` varchar(30) NOT NULL COMMENT '创建人名称', `create_time` datetime(3) DEFAULT NULL COMMENT '创建日期', `update_user_id` bigint DEFAULT NULL COMMENT '修改人ID', `update_user_name` varchar(30) DEFAULT NULL COMMENT '修改人名称', `update_time` datetime(3) DEFAULT NULL COMMENT '修改时间', `is_del` tinyint(1) DEFAULT '0' COMMENT '是否删除 1：已删除 0：未删除', PRIMARY KEY (`id`) USING BTREE) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8mb4 COMMENT='业务日志表';
